class Solution {
public:
    int leastOpsExpressTarget(int x, int target) {
        int res = INT_MAX;
        for (int i = 1; i <= target; i *= x) {
            int ops = 0;
            while (i * x <= target) {
                i *= x;
                ops++;
            }
            res = min(res, ops + (target - i + x - 1) / (x - 1));
        }
        return res;
    }
};
```

